public class Main {
    public static void main(String[] args) {
        String number1 = "17592";
        String number2 = "56781";
        System.out.println(addNumbers(number1, number2));
    }

    public static String addNumbers(String number1, String number2) {
        StringBuilder str1 = new StringBuilder();
        StringBuilder str2 = new StringBuilder();

        int len1 = number1.length();
        int len2 = number2.length();

        for (int i = 0; i < Math.max(len1, len2); i++) {
            if (i >= len1) {
                str1.append('0');
            } else {
                str1.append(number1.charAt(len1 - 1 - i));
            }

            if (i >= len2) {
                str2.append('0');
            } else {
                str2.append(number2.charAt(len2 - 1 - i));
            }
        }

        str1.reverse();
        str2.reverse();

        int carry = 0;
        StringBuilder result = new StringBuilder();

        for (int i = 0; i < Math.max(len1, len2); i++) {
            int sum = carry;
            if (i < len1) {
                sum += str1.charAt(i) - '0';
            }
            if (i < len2) {
                sum += str2.charAt(i) - '0';
            }
            result.append(sum % 10);
            carry = sum / 10;
        }

        if (carry > 0) {
            result.append(carry);
        }

        return result.reverse().toString();
    }
}
